package controllers

import play.api.mvc._
import play.api.Environment
import javax.inject._
import java.io.File
import java.nio.file.{Path, Paths}
import scala.io.Source
import scala.util.control.NonFatal

/**
 * Controller to serve user files from the 'uploads' directory.
 * It includes path traversal prevention.
 *
 * IMPORTANT NOTE: This implementation uses `scala.io.Source.fromFile` and reads the entire file
 * into a String using `mkString`. This is suitable for text files and small files,
 * but it is inefficient and potentially problematic for large binary files (e.g., images, PDFs)
 * as it consumes a lot of memory and assumes text encoding.
 *
 * For serving arbitrary file types and large files in a production environment,
 * it is highly recommended to use `Ok.sendFile(file, inline = true)` which handles
 * streaming, content-type detection, and efficiency much better.
 */
@Singleton
class FileController @Inject()(
  val controllerComponents: ControllerComponents,
  environment: Environment // Injected to get the application's root path
) extends BaseController {

  private val uploadsDirectoryName = "uploads"
  // Resolve the 'uploads' directory relative to the application's root path.
  // This assumes an 'uploads' directory exists at the same level as 'app', 'conf', 'public' etc.
  private val uploadsDirPath: Path = environment.rootPath.toPath.resolve(uploadsDirectoryName)

  def serveFile(filename: String) = Action {
    // 1. Path Traversal Prevention
    // Resolve the requested filename against the uploads directory path.
    // Normalize removes redundant elements like "." and ".." (e.g., "dir/../file" becomes "file").
    val targetPath: Path = uploadsDirPath.resolve(filename).normalize()

    // Ensure the normalized path still starts with the uploads directory path.
    // If it doesn't, it means path traversal (e.g., "../../etc/passwd") was attempted.
    if (!targetPath.startsWith(uploadsDirPath)) {
      BadRequest("Invalid file path. Path traversal detected.")
    } else {
      val file: File = targetPath.toFile

      if (!file.exists()) {
        NotFound("File not found.")
      } else if (file.isDirectory) {
        // Prevent serving directory listings
        BadRequest("Cannot serve a directory. Please specify a file.")
      } else {
        // 2. Read the file content
        var source: Option[Source] = None
